generated_oml:
// ---------- Sensing Components ----------
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor measuring armature current I_M on the permanent‑magnet synchronous motor."
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Encoder mounted on the motor shaft providing motor angle r_M."
    DTDFVocab:producedData MotorEncoderDataTransmitted
]

instance GearboxEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the gearbox providing output angle r_out."
    DTDFVocab:producedData GearboxEncoderDataTransmitted
]

// ---------- Data Transmitted ----------
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderSensor
]

instance GearboxEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoderSensor
]

// ---------- Raw Measured Data ----------
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Measured motor current I_M streamed via MQTT."
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo MATLABSimulinkEnabler, WebDashboardEnabler
]

instance MotorAngleData : DTDFVocab:Data [
    base:desc "Measured motor shaft angle r_M (encoder) streamed via MQTT."
    DTDFVocab:fromData MotorEncoderDataTransmitted
    DTDFVocab:inputTo MATLABSimulinkEnabler, WebDashboardEnabler
]

instance GearboxOutputAngleData : DTDFVocab:Data [
    base:desc "Measured gearbox output angle r_out (secondary encoder) streamed via MQTT."
    DTDFVocab:fromData GearboxEncoderDataTransmitted
    DTDFVocab:inputTo MATLABSimulinkEnabler, WebDashboardEnabler
]

// ---------- Simulated / Derived Data ----------
instance SimulatedMotorAngleData : DTDFVocab:Data [
    base:desc "Simulated motor angle ^r_M generated by the Simulink motor model."
    DTDFVocab:inputTo WebDashboardEnabler
]

instance SimulatedGearboxAngleData : DTDFVocab:Data [
    base:desc "Simulated gearbox output angle ^r_out generated by the Simulink gearbox model."
    DTDFVocab:inputTo WebDashboardEnabler
]

instance UpdatedFrictionParametersData : DTDFVocab:Data [
    base:desc "Updated friction model parameters (static, kinetic, viscous) calculated in real time."
    DTDFVocab:inputTo WebDashboardEnabler, MQTTBrokerEnabler
]

// ---------- Engineering & Simulation Models ----------
instance SysMLStructuralModel : DTDFVocab:Model [
    base:desc "SysML block definition and internal block diagrams of the robot axis (motor, gearwheel gearbox, cycloidal gearbox)."
    DTDFVocab:inputTo SysMLEnabler
]

instance SimulinkMotorModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model of the permanent‑magnet synchronous motor dynamics."
    DTDFVocab:inputTo MATLABSimulinkEnabler
]

instance SimulinkGearwheelGearboxModel : DTDFVocab:Model [
    base:desc "Simulink model of the gearwheel gearbox including gear ratios and inertia."
    DTDFVocab:inputTo MATLABSimulinkEnabler
]

instance SimulinkCycloidalGearboxModel : DTDFVocab:Model [
    base:desc "Simulink model of the cycloidal gearbox used for machining tasks."
    DTDFVocab:inputTo MATLABSimulinkEnabler
]

instance SimulinkFrictionModelCoulombViscous : DTDFVocab:Model [
    base:desc "Simulink friction model implementing Coulomb‑Viscous behaviour for the gearbox."
    DTDFVocab:inputTo MATLABSimulinkEnabler
]

instance SimulinkFrictionModelStribeck : DTDFVocab:Model [
    base:desc "Simulink friction model implementing Stribeck characteristic for the gearbox."
    DTDFVocab:inputTo MATLABSimulinkEnabler
]

// ---------- Enablers ----------
instance SysMLEnabler : DTDFVocab:Enabler [
    base:desc "SysML toolchain for structural and behavioural modeling of the robot axis."
]

instance MATLABSimulinkEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink environment for executable simulation of motor, gearbox, and friction models."
    DTDFVocab:enables FrictionIdentificationService, FrictionModelUpdateService
]

instance MQTTBrokerEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker providing real‑time streaming of sensor data to the digital twin."
    DTDFVocab:enables VisualizationService, FrictionIdentificationService
]

instance WebDashboardEnabler : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard for visualizing measured and simulated data streams."
    DTDFVocab:enables VisualizationService, FrictionModelUpdateService
]

// ---------- Services ----------
instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Real‑time identification of gearbox friction parameters (static, kinetic, viscous)."
    DTDFVocab:provides FrictionParametersInsight
]

instance VisualizationService : DTDFVocab:Service [
    base:desc "Unified visualization of measured sensor data and simulated model outputs."
    DTDFVocab:provides RealTimeVisualizationInsight
]

instance FrictionModelUpdateService : DTDFVocab:Service [
    base:desc "Generation of updated friction model parameters and automatic feedback to robot controller."
    DTDFVocab:provides UpdateControlAlgorithmAction
]

// ---------- Insights ----------
instance FrictionParametersInsight : DTDFVocab:Insight [
    base:desc "Identified friction parameters are fed back to the robot controller to adjust control algorithms."
]

// ---------- Actions ----------
instance UpdateControlAlgorithmAction : DTDFVocab:Action [
    base:desc "Automatic update of robot control algorithm with newly identified friction parameters to improve positional accuracy."
    DTDFVocab:IsAutomatic true
]

instance RealTimeVisualizationInsight : DTDFVocab:Insight [
    base:desc "Live dashboard display of measured vs. simulated angles and currents facilitates operator monitoring."
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "None – the digital shadow does not push data back to the physical robot."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A purpose‑driven digital shadow architecture that instantiates the Digital Shadow Reference Model: purpose (FrictionDerivation), asset (MABI axis), sources (sensors), processing components (simulation models), and data traces linked through traceability relations."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operational stage – the digital shadow is created and used during runtime to monitor and improve the robot’s motion accuracy."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Combines white‑box analytical friction models with black‑box data‑driven models; continuous identification ensures models stay valid as wear or load conditions change; traceability of each data point to its source and processing model enables verification by comparing simulated friction‑less behavior with measured data."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data are transmitted to the digital shadow via the MQTT publish/subscribe protocol; Asset Administration Shells are used to bind model elements to physical components."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Asset Administration Shell (AAS) is employed, aligning with Industrie 4.0/IEC standards for digital twin integration."
]
